fn create_engine(args: &[magnus::Value]) -> Result<CrawlEngineHandle, Error> {
    let args = magnus::scan_args::scan_args::<(), (Option<magnus::Value>,), (), (), (), ()>(args)?;
    let (config,) = args.optional;

    let config: Option<kreuzcrawl::CrawlConfig> = match config {
        Some(_v) if !_v.is_nil() => {
            let binding_val: CrawlConfig = CrawlConfig::try_convert(_v).map_err(|e| {
                magnus::Error::new(unsafe { Ruby::get_unchecked() }.exception_type_error(), e.to_string())
            })?;
            Some(binding_val.into())
        }
        _ => None,
    };
    let result = kreuzcrawl::create_engine(config.map(Into::into)).map_err(|e| {
        magnus::Error::new(
            unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
            e.to_string(),
        )
    })?;
    Ok(CrawlEngineHandle {
        inner: Arc::new(result),
    })
}

fn scrape(engine: CrawlEngineHandle, url: String) -> Result<ScrapeResult, Error> {
    let rt = tokio::runtime::Runtime::new().map_err(|e| {
        magnus::Error::new(
            unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
            e.to_string(),
        )
    })?;
    let result = rt
        .block_on(async { kreuzcrawl::scrape(&engine.inner, &url).await })
        .map_err(|e| {
            magnus::Error::new(
                unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
                e.to_string(),
            )
        })?;
    Ok(result.into())
}

